(91942, '{"citation":"Un partage d''une activit\\u00e9 avec un regard sans jugement par rapport au handicap autour d''une m\\u00eame passion \\"le handball\\".","phenomenal":"Stand d''information sur le Mondial 2017","quisuisje":"clubligue","partners":"Ville de Marseille - Ligue Provence Alpes - Mutuelle des services publics - Mutualit\\u00e9 Fran\\u00e7aise","participants":"300"}'),
(91944, '{"citation":"Information & communication autours de l''\\u00e9quipe de France et du Mondial 2017.\\nInformation & communication autours des animations propos\\u00e9s localement \\u00e0 l''occasion du Mondial 2017.\\n\\n","phenomenal":"Olymp''Hand 2016 sera aux couleurs du Mondial 2017. Nous mettons en place :\\nLes 20 Ecoles Primaires au cours de la journ\\u00e9e auront leur nom associ\\u00e9 au nom d''un joueur de l''\\u00e9quipe de France.\\nLes 24 terrains du tournoi de handball seront nomm\\u00e9s et rep\\u00e9r\\u00e9s aux couleurs d''un pays participant.\\nNous transmettons dans un premier temps un document explicatif du handball et du mondial dans les 20 \\u00e9coles. Puis 2 semaines avant le tournoi nous leur transmettrons un Quizz qu''elles devront compl\\u00e9ter et nous transmettre, des lots seront mis en jeu. Durant la journ\\u00e9e des questions seront pos\\u00e9s au micro et des lots seront mis en jeu.\\nUn Barnum aux couleurs du Mondial 2017 pr\\u00e9sentera Affiches, Photos, et document sur le Mondial 2017.","quisuisje":"club","partners":"La ville d\\u2019Orl\\u00e9ans, la ligue du Centre-Val de Loire de HandBall, le coll\\u00e8ge DUNOIS, FORMASAT et le SDIS 45","participants":"1800"}'),
(91999, '{"citation":"d\\u00e9couvrir l''ambiance du handball","quisuisje":"club","phenomenal":"information sur la billetterie du mondial et information sur le mondial, car nous visons une population qui d\\u00e9couvre le handball","participants":"20"}'),
