(93689, '{"citation":"Un super mondial fait d''\\u00e9motion! une accessibilit\\u00e9 et des regroupements organiser par le club pour voir les matchs t\\u00e9l\\u00e9vis\\u00e9s","phenomenal":"Publicit\\u00e9 dans le Cosec sur le mondial 2017 (calicots) + annonces verbales.","quisuisje":"club","partners":"Mairie de Mirecourt, Office Municipal des Sports, Communaut\\u00e9 de Commune de Mirecourt","participants":"80"}'),
(93690, '{"citation":"Faites comme vos enfants ou vos amis, venez d\\u00e9couvrir en toute convivialit\\u00e9 sur le terrain leur passion du handball, notre sport aux dix titres internationaux ! Avec peut-\\u00eatre un onzi\\u00e8me titre en vue lors du Mondial 2017 en France ?\\nPartagez ensuite notre pot de l''amiti\\u00e9 et notre soir\\u00e9e festive !","phenomenal":"Informations sur le Mondial 2017, en particulier concernant les sites de Nantes et de Brest.","quisuisje":"club","participants":"80"}'),
(93747, '{"citation":"De passer une tr\\u00e8s belle journ\\u00e9e de handball sous le signe de la bonne humeur...","phenomenal":"Chaque classe doit nous remettre un message de soutien \\u00e0 l''\\u00e9quipe de France. Ces messages seront coll\\u00e9s sur un support et envoy\\u00e9s \\u00e0 la FFHB","quisuisje":"comite","partners":"UGSEL, USEP, UNSS, Inspection acad\\u00e9mique, Ligue Alsace, Conseil D\\u00e9partemental, Cr\\u00e9dit Mutuel, Transport Transdev, March\\u00e9 Grand Frais, ","participants":"3000"}'),
