(145465, '{"citation":"Un billet pour les championnats du monde pour chacun des participants.","phenomenal":"Reproduction \\u00e0 l''identique du tournoi des championnats du monde, chaque \\u00e9quipe repr\\u00e9sentera une \\u00e9quipe national avec des maillots aux couleurs des pays. Le d\\u00e9roulement et les qualifications suivront le mod\\u00e8le du mondial","quisuisje":"club","partners":"Coll\\u00e8ge L\\u00e9on Blum de Villepreux, L''USMC des Clayes et la Municipalit\\u00e9.","participants":"52"}'),
(145469, '{"citation":"Les gagnants feront partis des participants aux rencontres du Mondial 2017 sur les sites de PARIS et MONTPELLIER","quisuisje":"clubligue","phenomenal":"Mise en place de tournois masculins, f\\u00e9minins, mixtes de handball 4 contre 4 avec stand d''information sur le Mondial 2017, mise en place d''\\u00e9crans avec vid\\u00e9os en continue sur les Mondiaux pr\\u00e9c\\u00e9dents, mise en place de Quizz.","participants":"150"}'),
(145470, '{"citation":"Participation aux matches du Championnat du Monde sur les sites de PARIS et MONTPELLIER.\\nLes r\\u00e9compenses seront attribu\\u00e9es aux clubs \\"m\\u00e9ritants\\" au nombre de participantes et \\u00e0 la dynamique impuls\\u00e9e.","phenomenal":"LORS DE CES JOURNEES, MISE EN PLACE DE \\"STANDS\\" D''INFORMATION SUR L''EVENEMENT DU MONDIAL: COMPOSITION DES POULES ET SITES, BILLETERIE, VIDEO","quisuisje":"clubligue","partners":"Union Nationale Sport Scolaire","participants":"100"}'),
(145477, '{"citation":"Les participants sont des clubs.\\nLes nomin\\u00e9s se verront remettre un quota de places sur des rencontres du Championnat du Monde sur les sites de Paris et Montpellier.","quisuisje":"clubligue","phenomenal":"Confection d''un LABEL \\u00e0 l''\\u00e9figie du Mondial 2017 pour r\\u00e9compenser les nomin\\u00e9s.","participants":"11"}'),
(145597, '{"citation":"De passer un bon moment d''\\u00e9changes et de partage autour d''un ev\\u00e8nement handball","phenomenal":"Travail en amont dans les classes sur les pays participants au mondial 2017 : drapeau, langue, monnaie et localisation","quisuisje":"Collectivite","participants":"150"}'),
(145600, '{"citation":"Vivre une exp\\u00e9rience unique \\u00e0 travers un dispositif adapt\\u00e9","quisuisje":"Collectivite","partners":"FFH et organes d\\u00e9concentr\\u00e9s, clubs parisiens","participants":"10000","phenomenal":"Information billetterie, pr\\u00e9sence des mascotte, places \\u00e0 gagner, d\\u00e9dicaces joueurs professionnels"}'),
(145603, '{"citation":"EN ATTENTE","phenomenal":"Quelques licenci\\u00e9s du club seront pr\\u00e9sent pour animer un tournoi, mettre en place des ateliers \\net un stand d''Informations ","quisuisje":"club","participants":"100"}'),
(145607, '{"citation":"De passer un moment convivial et de faire du handball dans le respect et la bon humeur","phenomenal":"Mise en place dans l\\u2019enceinte d''une salle des sport de Wattrelos  un  tournoi  co organis\\u00e9 avec les jeunes\\n\\nCe tournoi regroupera 6 \\u00e9quipes de 9 jeunes de 13 \\u00e0 17 ans, issues des quartiers class\\u00e9s en g\\u00e9ographie prioritaire politique de la ville  ( centres sociaux-maisons des jeunes ). Chaque \\u00e9quipes repr\\u00e9sentera une nation qualifi\\u00e9e\\n\\nAU CHAMPIONNAT DU MONDE 2017 de Handball. Dans un souci de valorisation des comp\\u00e9tences des jeunes issus des territoires class\\u00e9s en g\\u00e9ographie   Prioritaire   Politique   de   la   Ville   et   recherchant   sans   cesse   leur   participation   active,   des responsabilit\\u00e9s, une autonomie dans la conduite du projet  leur seront confi\\u00e9es. Le tournoi sera l '' aboutissement de plusieurs s\\u00e9ances d''initiation dans le cadre des accueils collectifs de mineurs des centres sociaux et de la Maison pour tous de la Martinoire afin de promouvoir les valeurs de la discipline \\n\\nRespect\\n\\nEnvie\\n\\nSport\\n\\nPlaisirs\\n\\nEnvie\\n\\nCitoyennet\\u00e9\\n\\nTol\\u00e9rance\\n\\n\\n\\nLa finalit\\u00e9 sera d''aller voir un match de handball au championnat du Monde de handball  2017 ","quisuisje":"Autre","partners":"CENTRE SOCIAUX DE WATTRELOS MAISON DES JEUNES DE WATTRELOS","participants":"50"}'),
(145644, '{"citation":"Possibilit\\u00e9 de gagner des places","phenomenal":"Stand d''information sur le Mondial\\n","quisuisje":"comite","partners":"UNSS 93, LIFE","participants":"200"}'),
(145656, '{"citation":"Participer au Mondial de Hand-ball 2017","phenomenal":"Articles \\u00e9crits par les \\u00e9l\\u00e8ves dans le journal du coll\\u00e8ge.","quisuisje":"Ecole","participants":"66"}');
INSERT INTO `${schema}` (`id`, `custom_fields`) VALUES
(145666, '{"citation":"D\\u00e9couvrir une activit\\u00e9 qui n''a pas encore \\u00e9t\\u00e9 propos\\u00e9 aux sportifs licenci\\u00e9s du Comit\\u00e9 D\\u00e9partemental de Sport Adapt\\u00e9 du Calvados.\\nS''amuser sur une activit\\u00e9 nouvelle et ludique\\nRencontrer des joueuses professionnelles du Club de Colombelles ainsi que du Club des Viking de Caen","quisuisje":"AutreAssociationSportive","phenomenal":"Stand d''information\\ncourrier d''information\\nparticipation de joueurs \\/ joueuses professionnel(le)s","participants":"90","partners":"Club La\\u00efque Colombellois, Soci\\u00e9t\\u00e9 G\\u00e9n\\u00e9rale, Harmonie Mutuelle, Conseil G\\u00e9n\\u00e9ral du Calvados, Viking du Caen HB"}'),
(145678, '{"citation":"Une journ\\u00e9e intense de joie, de partage et de plaisir.","phenomenal":"Stand d''information et de pr\\u00e9sentation du mondial 2017","quisuisje":"comiteligue","partners":"Usep 59, Fac des sports Universit\\u00e9 de Lille 2, FFHB, Etat.","participants":"250"}'),
(145764, '{"citation":"Offrir des places du mondial aux 4 \\u00e9quipes finaliste du tournoi du 26 janvier","phenomenal":"stand d''information sur le mondial, nom de pays aux \\u00e9quipes participantes","quisuisje":"ligue","participants":"500"}'),
(145882, '{"citation":"Vivre ensemble !","quisuisje":"usep","partners":"Comit\\u00e9 de handball 69 et la Ligue de Handball Rh\\u00f4ne Alpes","participants":"2000","phenomenal":"Organiser des rencontres sportives USEP de handball sur l''ensemble du territoire du d\\u00e9partement du Rh\\u00f4ne et de la M\\u00e9tropole de Lyon, avant, pendant et apr\\u00e8s le mondial 2017.\\nCommuniquer en amont et le jour des rencontres USEP sur l\\u2019\\u00e9v\\u00e9nement en directions des adh\\u00e9rents USEP (enfants et adultes) et parents accompagnateurs."}'),
(145888, '{"citation":"Ceux qui ont particip\\u00e9 au flashmob seront prioritaires pour venir assister aux matchs du mondial 2017.","quisuisje":"unss","phenomenal":"Nous allons participer avec les \\u00e9l\\u00e8ves de notre Association Sportive au Flashmob organis\\u00e9 par la FFHB pour promouvoir le mondial de Handball 2017. Le lundi midi, les \\u00e9l\\u00e8ves de l''AS travailleront sur la chor\\u00e9graphie an compagnie de deux enseignants dans le but de cr\\u00e9er la vid\\u00e9o et de la poster sur DailyMotion.","participants":"20"}'),
(145903, '{"citation":"Passer un super bon moment handball !","phenomenal":"La caravane du hand est un outil de promotion puisque les calicots sont marqu\\u00e9s aux couleurs du Mondial. L''information est diffus\\u00e9e","quisuisje":"clubligue","participants":"200"}'),
(146004, '{"citation":"Participer \\u00e0 l''une des rencontre se d\\u00e9roulant au stade Pierre Mauroy ","quisuisje":"Autre","phenomenal":"Participation au Ph\\u00e9nom\\u00e9nal Stadium des centres sociaux. Actions ph\\u00e9nom\\u00e9nales avec le club de Douai.","partners":"Ligue NPDC de handball","participants":"100"}'),
