(146410, '{"citation":"Vivre l''un des plus beaux moments de leur scolarit\\u00e9 sportive !","phenomenal":"Expos\\u00e9s sur les moments marquants des pr\\u00e9c\\u00e9dents mondiaux et sur le fabuleux parcours de l''\\u00e9quipe de France lors de ces derni\\u00e8res ann\\u00e9es.","quisuisje":"unss","participants":"100"}'),
(146443, '{"citation":"Rencontrer les joueurs Pro du club de Massy Essonne Handball\\nAssister \\u00e0 un match des championnats du Monde","phenomenal":"Rencontre \\u00e9v\\u00e8nementielle \\"vivre-ensemble\\" des deux \\u00e9coles des zones sensibles (Brunoy et Massy) pour un tournoi final de Hand \\u00e0 4 en partenariat avec les joueurs de la Proligue du Massy Essonne Handball","quisuisje":"clubcomite","partners":"Education Nationale, le club de Massy Essonne Handball, la DDCS et le Conseil d\\u00e9partemental (91)","participants":"180"}'),
(146487, '{"citation":"La promesse de passer une journ\\u00e9e agr\\u00e9able en pratiquant le handball juste avant les f\\u00eates de fin d''ann\\u00e9e, et \\u00e0 quelques semaines du Mondial.\\nPlaisir, convivialit\\u00e9 et d\\u00e9couverte du handball pour notamment des publics qui ne pratiquent pas habituellement sont les ma\\u00eetres-mots de notre \\u00e9v\\u00e9nement.","quisuisje":"club","partners":"Ligue de Normandie de Handball, Ville de Colombelles, Conseil D\\u00e9partementale du Calvados, Conseil R\\u00e9gional de Normandie, CNDS, entreprises locales","participants":"130","phenomenal":"Plusieurs animation autour du Mondial sont pr\\u00e9vues parall\\u00e8lement :\\n\\n- Rediffusion du documentaire sur l''\\u00e9quipe de France \\"Des Barjots aux Experts, 20 ans de handball fran\\u00e7ais\\" dans une salle d\\u00e9di\\u00e9e.\\u00a0La projection est enti\\u00e8rement gratuite, et accessible \\u00e0 tous (m\\u00eame les non-inscrits au tournoi).\\n\\n- Animations propos\\u00e9es par la Ligue de Normandie de Handball (Ateliers de tir, pr\\u00e9cision et stand information sur le Mondial 2017, tout public \\u00e9galement)."}'),
(146537, '{"citation":"Participation \\u00e0 un match du mondial","phenomenal":"Atelier sur les sites d''accueil - les villes - les \\u00e9quipes\\nAtelier Photos pour la mosa\\u00efque\\nStand d''informations sur les billets\\n","quisuisje":"club","participants":"180","partners":"CIC - Go Sport - Le Vestiaire"}'),
