(146777, '{"citation":"\\u00catre de fervents supporters et passer un moment inoubliable.","quisuisje":"Autre","phenomenal":"Soutenir les \\u00e9quipes pr\\u00e9sentes au tournoi et profiter de l''ambiance de ce grand \\u00e9v\\u00e9nement malgr\\u00e9 les difficult\\u00e9s individuelles.","participants":"9"}'),
(146789, '{"citation":"Possibilit\\u00e9 d''aller voir un match du Mondial si nous b\\u00e9n\\u00e9ficions de place par la Ligue Midi-Pyr\\u00e9n\\u00e9es Handball ainsi que le transport vers Montpellier si on b\\u00e9n\\u00e9ficie d''une aide de la ligue ","phenomenal":"Il y aura un stand o\\u00f9 les jeunes procurer d''affiches du mondial. Des posters seront affich\\u00e9s lors de l''\\u00e9v\\u00e9nement","quisuisje":"club","participants":"80"}'),
(146826, '{"citation":"Possibilit\\u00e9 d''avoir des places pour un match du mondial \\u00e0 Montpellier si la Ligue Midi-Pyr\\u00e9n\\u00e9es peut en fournir. ","phenomenal":"les affiches du mondial seront affich\\u00e9es au gymnase, nous donneront \\u00e9galement \\u00e0 chaque jeunes un flyer du Mondial","quisuisje":"club","participants":"100"}'),
(146837, '{"citation":"d\\u00e9couverte du handball par la pratique de haut niveau jeunes par le mondialito et la possibilit\\u00e9 d''assister \\u00e0 une rencontre du championnat du monde \\u00e0 Bercy","phenomenal":"faire participer les \\u00e9l\\u00e8ves de la commune \\u00e9coles primaires, coll\\u00e8ges et lyc\\u00e9e en tant que spectateur au tournoi \\" mondialito\\" organis\\u00e9 sur la ville du 15 au 22 janvier 2017","quisuisje":"Collectivite","partners":"club de pontault-combault handball, \\u00e9ducation nationale","participants":"500"}'),
(146838, '{"citation":"OBTENTION DE PLACE POUR LE MONDIAL 2017","quisuisje":"Collectivite","partners":"","phenomenal":"Stand d''information billetteries, matchs retransmis sur Grand Ecran  ","participants":"598"}'),
(146844, '{"citation":"Aller voir un match du mondial 2017 dans la salle de L\\u2019AccorHotels Arena.\\nOrganis\\u00e9es par la F\\u00e9d\\u00e9ration fran\\u00e7aise de handball (FFHB), les Rencontres nationales Handensemble sont un formidable vecteur d\\u2019inclusion et de partage. Le handicap \\u00e9tant la grande cause du Championnat du monde 2017 de handball, le Comit\\u00e9 d\\u2019organisation France 2017 est associ\\u00e9 \\u00e0 cet \\u00e9v\\u00e9nement avec Handicap International.","phenomenal":"Organiser des matches de handball au sein des centres de loisirs\\nContribuer \\u00e0 la mise en \\u0153uvre d\\u2019\\u00e9v\\u00e8nements pr\\u00e9conisant la pratique sportive comme vecteurs de bonne sant\\u00e9 physique ou mentale, de lutte contre la s\\u00e9dentarisation, de bonne hygi\\u00e8ne de vie et de pr\\u00e9vention des risques de maladies.\\nL\\u2019exercice physique est de moins en moins int\\u00e9gr\\u00e9 aux activit\\u00e9s de la vie quotidienne telles que le travail ou les d\\u00e9glacements. Les cons\\u00e9quences sanitaires de cette \\u00e9volution des modes de vie vers une plus grande s\\u00e9dentarisation inqui\\u00e8tent les pouvoirs publics. M\\u00eame si de plus en plus de personnes s\\u2019adonnent aux activit\\u00e9s physiques ou sportives pendant leurs loisirs, la majorit\\u00e9 de la population n\\u2019atteint pas le niveau d\\u2019activit\\u00e9 physique hebdomadaire requis pour un effet b\\u00e9n\\u00e9fique sur la sant\\u00e9.\\n\\uf0e0 Proposer un \\u00e9ventail d\\u2019activit\\u00e9s sportives\\n\\uf0e0 Mettre du lien les populations et les associations sportives\\n\\uf0e0 Informer et pr\\u00e9venir des risques de maladies\\n","quisuisje":"Collectivite","partners":"La FFHB, Le CSAKB, Le reseau information jeunesse, le service jeunesse","participants":"20"}'),
(146845, '{"citation":"S''amuser, d\\u00e9couvrir, partager...\\nAller voir un match du mondial 2017 dans la salle de L\\u2019AccorHotels Arena.","quisuisje":"Collectivite","partners":"ALSH espace jeunesse, CSAKB","participants":"8","phenomenal":"1- Tournoi mixte, 8\\/11 ans\\n2- Avoir un minimum de 5 joueurs"}'),
(146846, '{"citation":"rencontre de J. Richardson lors du challenge \\u00e0 Dijon","phenomenal":"Rencontre avec un ancien international de hand ball, entra\\u00eeneur(J. Richardson) lors du challenge Michelet \\u00e0 Dijon en mai 2017.\\nValorisation du mondial lors des journ\\u00e9es de regroupements ritualis\\u00e9es, \\u00e9changes sur la citoyennet\\u00e9 \\u00e0 l''\\u00e9chelle mondiale, et les notions d''identit\\u00e9","quisuisje":"AssoCulturelle","partners":"PJJ, P\\u00f4le ressource SEMC, CREPS Paca, d\\u00e9l\\u00e9gation d\\u00e9partementales UFOLEP, d\\u00e9l\\u00e9gation r\\u00e9gionale L\\u00e9o Lagrange, Conseil r\\u00e9gional PACA, pr\\u00e9fecture des Bouches-du-Rh\\u00f4ne (FIPD), DRJSCS","participants":"200"}'),
(146884, '{"citation":"Participer activement \\u00e0 la grande f\\u00eate du handball li\\u00e9e \\u00e0 l''accueil du Championnat du Monde en France .","phenomenal":"Caravane aux couleurs du mondial. Informations sur l''organisation du championnat du Monde du Handball. D\\u00e9couverte de l''Equipe de France au travers d''un quizz. Distribution de flyers, goodies et t-shirts. Participation \\u00e0 la mosa\\u00efque.","quisuisje":"clubligue","partners":"Clubs de Midi-Pyr\\u00e9n\\u00e9es","participants":"5000"}'),
(146887, '{"citation":"Etre dans une forme ph\\u00e9nom\\u00e9nale pour suivre le Mondial en pleine sant\\u00e9","phenomenal":"Information sur la billetterie. ","quisuisje":"comiteligue","partners":"Comit\\u00e9s et clubs. Nutritionniste","participants":"300"}'),
(146892, '{"citation":"Decouvrir est de prodiguer les valeur de la solidariter a travers le handball","quisuisje":"club","phenomenal":"a gagner des place pour le mondial 2017","partners":"","participants":"60"}'),
