(147060, '{"citation":"Cette manifestation est l''assurance, pour les enfants, de participer \\u00e0 des activit\\u00e9s ludiques, nouvelles, int\\u00e9ressantes, en lien avec les valeurs de l''olympisme. ","quisuisje":"AutreAssociationSportive","partners":"USEP Nord, comit\\u00e9s d\\u00e9partementaux sportifs, municipalit\\u00e9","participants":"350","phenomenal":"Promotion de l''\\u00e9v\\u00e9nement"}'),
