(147388, '{"citation":"D\\u00e9s r\\u00e9compenses \\u00e0 l''effigie du Mondial","phenomenal":"La MAscotte du Mondial Rok a \\u00e9t\\u00e9 pr\\u00e9sente et des goodies \\u00e0 l''effigie du Mondial avec des flyers d''informations sur les matchs \\u00e0 Montpellier ont \\u00e9t\\u00e9 distribu\\u00e9s","quisuisje":"comiteligue","partners":"H\\u00e9rault Sport Club d''Agde HB et comit\\u00e9 et Ligue de sport adapt\\u00e9","participants":"100"}'),
(147397, '{"citation":"Un spectacle de handball ph\\u00e9nom\\u00e9nal qui vous donnera envie d''entrer dans l''ar\\u00e8ne du Hand !!!","quisuisje":"AutreAssociationSportive","participants":"50","phenomenal":"POUR LE CHAMPIONNAT DU MONDE DE HANDBALL, nous souhaitons mobiliser notre communaut\\u00e9 de femmes sportives nantaises pour leur faire d\\u00e9couvrir le handball.\\nNotre communaut\\u00e9 compte sur Facebook et sur notre mailing liste plus de 3000 femmes sur la r\\u00e9gion nantaise.\\nNous les invitons le 15 octobre prochain sur un match du NLAH et elles sont d\\u00e9j\\u00e0 plus de 150 \\u00e0 avoir r\\u00e9pond pr\\u00e9sentes.\\nNous souhaitons inviter un groupe \\u00e0 assister \\u00e0 un match du Championnat du Monde de handball 2017 et susciter chez elles et\\/ou leurs proches l''envie de pratiquer le handball.\\n\\nPOUR CELA NOUS SOUHAITONS LEUR PROPOSER UN JEU CONCOURS sur les RESEAUX SOCIAUX.\\nCela consiste \\u00e0 publier sur Facebook ou Instagram une photo d''elle d\\u00e9guis\\u00e9e en supportrice en mentionnant les hashtag #JESUISPHENOMENALE #FRANCEHANDBALL2017 #LAFABRIQUESPORTIVE\\nLes 50 photos les plus appr\\u00e9ci\\u00e9es par le jury de notre association seront invit\\u00e9s \\u00e0 assister \\u00e0 un match du Championnat du monde de handball, \\u00e0 condition que l''appel \\u00e0 projet nous permette de b\\u00e9n\\u00e9ficier de billets pour cela."}'),
(147413, '{"citation":"- Places \\u00e0 tarif r\\u00e9duit\\n- Invitations pour un match de la coupe du Mon","quisuisje":"club","participants":"500","phenomenal":"Accueil du 14 \\u00e8me Troph\\u00e9e M\\u00e9diterran\\u00e9en de la Jeunesse (U17)"}'),
(147465, '{"citation":"Jouer, s''amuser.. et peut-\\u00eatre voir en janvier ses joueurs de handball pr\\u00e9f\\u00e9r\\u00e9s!","phenomenal":"Pr\\u00e9sence confirm\\u00e9e des mascottes Rok et Koolette le vendredi 28\\/10 en fin de matin\\u00e9e. Places \\u00e0 gagner pour le Mondial lors du tournoi et des challenges individuels","quisuisje":"Collectivite","participants":"288"}'),
(147475, '{"citation":"Assister \\u00e0 un match de Handball professionnel dans une salle sportive pleine et embl\\u00e9matique (Coubertin)... et vivre un spectacle sportif de haut-niveau dans une belle ambiance","quisuisje":"Collectivite","partners":"ISSY PARIS HANDBALL","participants":"4000","phenomenal":"Les 4000 enfants porteront chacun(e) un t-shirt aux couleurs du Mondial de HB 2017.\\nPr\\u00e9sence des mascottes Rok et Koolette envisag\\u00e9e sous r\\u00e9serve de disponibilit\\u00e9 en jour d''ouverture du Mondial"}'),
(147510, '{"citation":"Prendre plaisir \\u00e0 jouer autour d''une bonne action qui est le t\\u00e9l\\u00e9thon","phenomenal":"- Stand d''information \\n- communication \\u00e9v\\u00e8nementielle\\n- tee-shirt Mondial 2017 aux organisateurs dans la mesure du possible\\n- Remise de lots si possible","quisuisje":"club","partners":"Ligue de Bourgogne de Handball, Comit\\u00e9 de C\\u00f4te d''Or de Handball, mairie de Venarey-Les Laumes, Communaut\\u00e9 de COmmunes du Pays d''Al\\u00e9sia et de la Seine, Unsion Sportive Cheminote de venarey-Les Laumes","participants":"150"}'),
