(147594, '{"citation":"MOMENT CONVIVIAL AUTOUR DU HANDBALL ET EVENTUELLEMENT ALLER VOIR MATCH DU MONDIAL ","phenomenal":"STAND QUESTIONNAIRE PALMARES HANDBALL FRANCAIS","quisuisje":"club","partners":"MAIRIE","participants":"100"}'),
(147597, '{"citation":"Participer \\u00e0 une action de solidarit\\u00e9 nationale\\nS''initier au Handensemble\\nObtenir des places pour le Mondial \\u00e9ventuellement\\n","phenomenal":"Les personnes pourront gagner des places pour le Mondial au travers de la Tombola.\\n ","quisuisje":"club","partners":"AFM","participants":"200"}'),
(147599, '{"citation":"Vivre un moment d''exception, et la r\\u00e9alisation de son  r\\u00eave sport","phenomenal":"Afin de promouvoir l\\u2019\\u00e9v\\u00e9nement, nous allons organiser dans les villes h\\u00f4tes (Nantes, Rouen, Paris, Montpellier, Metz, Lille, Grenoble ; Lyon) des go\\u00fbters-d\\u00e9dicaces dans les services p\\u00e9diatriques des h\\u00f4pitaux de ces villes avec des animations hand-ball et accompagn\\u00e9s de handballeurs et handballeuses. La mise en place des go\\u00fbters est en cours d\\u2019\\u00e9laboration avec chaque \\u00e9tablissement, celui du centre hospitalier d''Arras, qui r\\u00e9unira une cinquantaine d''enfants et une dizaine de sportifs, est pr\\u00e9vu pour le 7 ou le 8 d\\u00e9cembre.","quisuisje":"Autre","partners":"Carrefour; P\\u00e9ricl\\u00e8s consulting","participants":"23"}'),
(147600, '{"citation":"Vivre un moment d\\u2019exception et la r\\u00e9alisation se son r\\u00eave sport.","phenomenal":"Afin de promouvoir l\\u2019\\u00e9v\\u00e9nement, nous allons organiser dans les villes h\\u00f4tes (Nantes, Rouen, Paris, Montpellier, Metz, Lille, Grenoble ; Lyon) des go\\u00fbters-d\\u00e9dicaces dans les services p\\u00e9diatriques des h\\u00f4pitaux de ces villes avec des animations handball et accompagn\\u00e9s de handballeurs et handballeuses. La mise en place des go\\u00fbters est en cours d\\u2019\\u00e9laboration avec chaque \\u00e9tablissement.","quisuisje":"Autre","partners":"Carrefour; P\\u00e9ricl\\u00e8s consulting","participants":"46"}'),
(147601, '{"citation":"R\\u00e9alisation de son r\\u00eave sport et vivre un moment exceptionnel. ","phenomenal":"Afin de promouvoir l\\u2019\\u00e9v\\u00e9nement, nous allons organiser dans les villes h\\u00f4tes (Nantes, Rouen, Paris, Montpellier, Metz, Lille, Grenoble ; Lyon) des go\\u00fbters-d\\u00e9dicaces dans les services p\\u00e9diatriques des h\\u00f4pitaux de ces villes avec des animations handball et accompagn\\u00e9s de handballeurs et handballeuses. La mise en place des go\\u00fbters est en cours d\\u2019\\u00e9laboration avec chaque \\u00e9tablissement.","quisuisje":"Autre","partners":"Carrefour; P\\u00e9ricl\\u00e8s consulting","participants":"23"}'),
(147602, '{"citation":"- Faire du handball dans notre \\u00e9cole une activit\\u00e9 sportive phare. \\n- Toi et moi nous sommes diff\\u00e9rents, par notre \\u00e9ducation, notre aspect physique mais nous avons besoin l''un de l''autre et ce sport collectif nous permet de nous d\\u00e9couvrir. ","quisuisje":"AutreAssociationSportive","partners":"club de handball de La Possession , usep","participants":"146","phenomenal":"Activit\\u00e9s sur le temps de la pause m\\u00e9ridienne,\\nactivit\\u00e9s EPS avec le professeur sur le temps p\\u00e9dagogique\\nrencontre et mise en situation d''unit\\u00e9 d''apprentissage en situation de handensemble\\nrencontre et \\u00e9change sportif avec les parents \\nrencontre avec des champions de la discipline"}'),
(147603, '{"citation":"VIVRE UN MOMENT D EXEPTION ET LA REALISATION SE SON R\\u00caVE SPORT","phenomenal":"Afin de promouvoir l\\u2019\\u00e9v\\u00e9nement, nous allons organiser dans les villes h\\u00f4tes (Nantes, Rouen, Paris, Montpellier, Metz, Lille, Grenoble ; Lyon) des go\\u00fbters-d\\u00e9dicaces dans les services p\\u00e9diatriques des h\\u00f4pitaux de ces villes avec des animations handball et accompagn\\u00e9s de handballeurs et handballeuses. La mise en place des go\\u00fbters est en cours d\\u2019\\u00e9laboration avec chaque \\u00e9tablissement, celui du centre hospitalier d''Arras, qui r\\u00e9unira une cinquantaine d''enfants et une dizaine de sportifs, est pr\\u00e9vu pour le 7 ou le 8 d\\u00e9cembre.","quisuisje":"Autre","partners":"Carrefour; P\\u00e9ricl\\u00e8s consulting","participants":"46"}'),
(147647, '{"citation":"Encourager l''\\u00e9quipe de France en finale","quisuisje":"Ecole","phenomenal":"\\"Tous experts !\\"\\nPromouvoir le hand : expos\\u00e9s oraux par mes \\u00e9l\\u00e8ves aux 5 classes de CM1 et CM2 de l''\\u00e9cole et productions d''articles pour le blog du coll\\u00e8ge ; pr\\u00e9sentation et des grands principes du Hand-ball, l''actualit\\u00e9 du Championnat du Monde et de l''\\u00e9quipe de France.\\nPartager collectivement l''\\u00e9v\\u00e9nement en organisant des soir\\u00e9es festives \\u00e0 l''\\u00e9cole : diffusion des matchs (quarts, demis et finale) dans le pr\\u00e9au avec lien aux familles (buffet dinatoire).","participants":"35","partners":"Usep (Philippe Robert), acad\\u00e9mie de Paris (Emmanuelle Pievic, IEN 18D)"}'),
(147658, '{"citation":"Rencontrer Mikkel Hansen et Nikola Karabatic au Mondial!!","phenomenal":"Organisation d''un tournoi (sur toute une journ\\u00e9e)\\nChoix par les \\u00e9l\\u00e8ves des noms d''\\u00e9quipes (pays qui participent au Mondial)","quisuisje":"edunat","partners":"Coll\\u00e8ge, \\u00e9coles primaires, le Comit\\u00e9 de Handball de l''Essonne, la Mairie de Vigneux Sur Seine","participants":"330"}'),
(147700, '{"citation":"Un entrainement avec la venue d''un joueur international (Randy BULA YIMA) jouant au club de Bois Colombes.","phenomenal":"Pour promouvoir la pratique du Hand-Ball dans les \\u00e9tablissements scolaires, et faire la promotion du mondial 2017, nous allons cette ann\\u00e9e avec les \\u00e9l\\u00e8ves de l''AS Hand et ceux des classes \\"promo sport\\" proposer des interventions dans des classes de CM2 de la commune.\\nNous envisageons \\u00e9galement de r\\u00e9aliser des panneaux d''affichages qui seraient expos\\u00e9s dans le coll\\u00e8ge au moment de mondial pour expliquer les r\\u00e8gles du jeux et faire suivre l''\\u00e9v\\u00e8nement aux autres \\u00e9l\\u00e8ves de l''\\u00e9tablissement. ","quisuisje":"unss","participants":"40"}'),
(147701, '{"citation":"de se r\\u00e9unir sous une meme passion bien que venant de milieu diff\\u00e9rent et ayant des possibilit\\u00e9s physiques diff\\u00e9rentes.","phenomenal":"affiches, r\\u00e9seaux sociaux et communication autour de l''\\u00e9v\\u00e8nement","quisuisje":"club","partners":"Service des sports Mairie de Saint S\\u00e9bastien de Morsent","participants":"200"}'),
