(147879, '{"citation":"Communication et promotion du Championnat du monde de Handball\\nTournoi avec des jeunes talents.","quisuisje":"comite","participants":"100","phenomenal":"Stand mosa\\u00efque, communication sur la billetterie. "}'),
(147881, '{"citation":"Prendre plaisir \\u00e0 jouer au Handball ","phenomenal":"Affichage particulier du mondial (drapeau ph\\u00e9nom\\u00e9nal, logo mondial, affichage, ...). \\nArticle dans journal de la ville reprenant la promotion du Handball autour du mondial","quisuisje":"club","partners":"acad\\u00e9mie de versailles, mairie de Bagneux, Club Omnisport de Bagneux (COMB)","participants":"520"}'),
(147889, '{"citation":"C''est celle d''assister \\u00e0 une rencontre du Mondial \\u00e0 Paris en janvier 2017 !!!\\nNous avons choisi 3 matches dans l''agenda ci-dessous, par ordre de pr\\u00e9f\\u00e9rence :\\n-1- France-Br\\u00e9sil\\n-2- Danemark-Su\\u00e8de\\n-3- Danemark-Bahrein","quisuisje":"Ecole","phenomenal":"- Participation \\u00e0 un tournoi inter-scolaire,\\n- Apprentissage des r\\u00e8gles et pratique de ce sport,\\n- Participation active en tant que supporter du handball, notamment lors d''une rencontre du Mondial,,\\n- D\\u00e9monstration aux autres classes de l''\\u00e9cole,\\n- Reportage photojournaliste lors de ces \\u00e9v\\u00e9nements;\\n\\n","participants":"60","partners":"USEP, Education Nationale, Ligue de r\\u00e9gion parisienne de handball"}'),
(147897, '{"citation":"Spectacle ph\\u00e9nom\\u00e9nale des Bleus\\n\\nPromotion et communication du Championnat du monde.\\n\\nPh\\u00e9nom\\u00e9nale Mosa\\u00cfQUE","quisuisje":"comite","participants":"1000","phenomenal":"Spectacle ph\\u00e9nom\\u00e9nale des Bleus\\n\\nPromotion et communication du Championnat du monde.\\n\\nPh\\u00e9nom\\u00e9nale Mosa\\u00cfQUE"}'),
(147912, '{"citation":"Voir ou assister \\u00e0 un match de handball lors du mondial.","quisuisje":"Ecole","partners":"Inspection Education Nationale ; USEP","participants":"86","phenomenal":"Communication dans les classes, travaux p\\u00e9dagogiques autour de l''\\u00e9v\\u00e8nement (EMC, g\\u00e9ographie, Sciences, EPS).\\nSuivi de l''\\u00e9v\\u00e8nement au sein des classes."}'),
(147941, '{"citation":"ce projet est construit pour permettre aux enfants participants d''avoir une vision plus pertinente du handball au travers une meilleure compr\\u00e9hension des r\\u00e8gles du jeu. \\nils seront donc plus attentifs, concern\\u00e9s en regardant et\\/ou en assistant aux matchs du mondial. ","phenomenal":"\\nAfin de sensibiliser, les participants au mondial 2017, un travail autour des r\\u00e8gles du jeu et de vie handball sera propos\\u00e9 dans les diff\\u00e9rentes groupes scolaires de la ville de Serris.\\n\\n","quisuisje":"Collectivite","partners":"les \\u00e9coles de la ville de Serris; service jeunesse, service animation ville de Serris","participants":"100"}'),
(147945, '{"citation":"Des places pour Rouen \\u00e0 certains.","quisuisje":"unss","phenomenal":"Pr\\u00e9sentation dans chacun des gymnases du Championnat du Monde et notamment de la Poule C qui se d\\u00e9roulera \\u00e0 Rouen ","partners":"Comit\\u00e9 de Handball de l''Eure","participants":"250"}'),
(147983, '{"citation":"R\\u00e9compenses pour tous les participants","phenomenal":"Habillage Mondial 2017, stand d''informations autour du Mondial 2017 et possibilit\\u00e9 de faire gagner des places.","quisuisje":"club","partners":"Ligue ile de France EST, CDHB 93, Mairie de Montreuil","participants":"150"}');
