(148050, '{"citation":"Un moment ludique dans une ambiance conviviale","phenomenal":"Un tournoi ludique afin de participer \\u00e0 un temps collectif autour de la pratique de handball","quisuisje":"Collectivite","participants":"50"}'),
(148052, '{"citation":"PARTAGER LA VICTOIRE DE L''EQUIPE DE FRANCE TOUS ENSEMBLE DEVANT LE MEME ECRAN LE 29\\/01\\/2017 !","quisuisje":"club","phenomenal":"FLYERS DANS LES GYMNASES + AFFICHES DANS LES GYMNASES + BANDEROLES DANS LES GYMNASES.","participants":"50"}'),
(148054, '{"citation":"assister \\u00e0 un match du mondial, participer \\u00e0 une journ\\u00e9e en partenariat avec la ligue de handball IDF en juin.","phenomenal":"Nous parlerons du handball, nous tiendrons inform\\u00e9s des \\u00e9v\\u00e9nements et des matchs, des pays partcipants, des r\\u00e9sultats et si possible aller voir un match \\u00e0 Bercy","quisuisje":"Ecole","participants":"60","partners":"usep"}'),
(148056, '{"citation":"Une bonne ambiance, un plaisir de jouer et soutenu par un public ph\\u00e9nom\\u00e9nal","phenomenal":"Affiches et tee-shirts du mondial sont offerts","quisuisje":"unss","participants":"80"}'),
(148067, '{"citation":"Tournoi de Handball sur le th\\u00e8me du Mondial avec les noms, les couleurs et les hymnes des \\u00e9quipes.","phenomenal":"Affiches, flyers, Tableau de suivi de comp\\u00e9tition","quisuisje":"unss","partners":"UNSS, Education Nationale, CDOS 61","participants":"130"}'),
