(148096, '{"citation":"Partager des moments de sport autour du handball et se construire autour de valeurs telles que le respect, la solidarit\\u00e9 et le vivre ensemble.\\nRencontrer les joueurs professionnels de l''\\u00e9quipe de France lors des matchs en Lidl Star Ligue aux stades de Flandres.","phenomenal":"Communication lors des matchs de l''USDK en Lidl Star Ligue\\nMise en avant du programme \\"Handballeur citoyen\\"","quisuisje":"Collectivite","partners":"Coll\\u00e8ge Van Hecke - Ecole Andr\\u00e9 Nita - USDK -Ville de Dunkerque","participants":"43"}'),
(148145, '{"citation":"D\\u00e9couverte et pratique du handball sur l''un des sites accueillant les matchs du Mondial 2017.","phenomenal":"Interventions dans les \\u00e9coles sur les temps scolaires et p\\u00e9ri scolaires (TAP), de septembre \\u00e0 juin (Albertville).\\nRoad Show (27 et 28 septembre 2016).\\nInterventions aupr\\u00e8s des coll\\u00e9giens sur le temps scolaire (Ugine), le 16 septembre 2016.\\nTournoi \\u00e0 la Halle Olympique (salle h\\u00f4te pour les matchs du Mondial 2017), le 25 octobre 2016.\\nTournoi sur glace (patinoire), le 7 d\\u00e9cembre 2016.","quisuisje":"club","partners":"Mairies d''Albertville et d''Ugine, Coral, Comit\\u00e9 de Savoie de Handball, Ligue Dauphin\\u00e9e Savoie de Handball.","participants":"300"}'),
(148147, '{"citation":"allez \\u00e0 Bercy \\nfaire d\\u00e9couvrir le hand ball\\n","phenomenal":"inscription sur place \\u00e0 la mosa\\u00efque , promotion des \\u00e9quipes nationales avec les cartes de la FFHB: calendrier des matchs en copies, participation avec les enfants et parents ,tous supporters \\u00e0 BERCY pour un match avec nos tee shirts  ph\\u00e9nom\\u00e9nal  .","quisuisje":"club","partners":"comite  ligue  entreprise","participants":"150"}'),
