(148636, '{"citation":"Le tournoi jeune du Handball Club Brotonne - Le Trait sera \\u00e9galement \\"Ph\\u00e9nom\\u00e9nal\\". Il s\\u2019agit du pari que va relever le HCBT gr\\u00e2ce \\u00e0 une organisation parfaite dans le but de faire de l\\u2019\\u00e9v\\u00e9nement une f\\u00eate populaire, accessible \\u00e0 tous et permettant aux publics de vivre une journ\\u00e9e exceptionnelle !","phenomenal":"- Mise en place d''un stand d\\u2019information sur la billetterie mondial","quisuisje":"club","partners":"LIDL France, Artemis, We Enjoy, Arelaune-En-Seine, Comit\\u00e9 76 Handball; Ligue de Normandie de Handball, Seine Maritime, Clubeo, R\\u00e9gion Normandie, Caux Seine Aglo, Horizom FM","participants":"120"}'),
(148654, '{"citation":"Participer, comme les handballeurs fran\\u00e7ais \\u00e0 un mondial de handball.","phenomenal":"-\\tFaire participer les licenci\\u00e9s \\u00e0 la mosa\\u00efque ph\\u00e9nom\\u00e9nale.\\n-\\tInformation sur la billetterie mondial.\\n-\\tRetransmission de matchs.\\n-\\tD\\u00e9placement pour un match de l\\u2019\\u00e9quipe de France \\u00e0 Nantes.\\n-\\t\\u00c9v\\u00e9nement de communication (promotion locale).\\n\\nL''\\u00e9v\\u00e9nement se passant apr\\u00e8s le Mondial 2017, nous esp\\u00e9rons cependant b\\u00e9n\\u00e9ficier d\\u2019effets de d\\u00e9corations de sites du Mondial pour recr\\u00e9er une ambiance similaire lors du tournoi. Le comit\\u00e9 d\\u2019organisation va \\u00eatre sollicit\\u00e9 (via la commission d\\u00e9veloppement f\\u00e9d\\u00e9rale) dans ce but, en consid\\u00e9rant notre proximit\\u00e9 avec le site de NANTES.","quisuisje":"club","partners":"UGSEL (convention nationale) \\u2013 Comit\\u00e9 79 Handball + partenaires priv\\u00e9s","participants":"1200"}'),
(148701, '{"citation":"Participation \\u00e0 une rencontre du mondial 2017","phenomenal":"Information sur la mondial et \\"mosa\\u00efque\\"","quisuisje":"club","participants":"250"}'),
