(149569, '{"citation":"achat de billets par le club et vente aux licenci\\u00e9s avec une partie de prise en charge club","phenomenal":"distribution des flyers\\npresentation de la video du Mondial\\npresentation des 2 b\\u00e9n\\u00e9voles du club qui participeront \\u00e0 ce bel \\u00e9v\\u00e8nement","quisuisje":"club","partners":"Ville de Pignan, entreprises partenaires (cic, julien dorcel, demeures d''occitanie, spar, peugeot...)","participants":"300"}'),
(149604, '{"citation":"Outil de soutien \\u00e0 l''\\u00e9quipe de France de handball","quisuisje":"comite","partners":"UNSS, USEP, Inspection Acad\\u00e9ique","participants":"750","phenomenal":"Stand information mondial"}'),
(149623, '{"citation":"Retour sur les messages envoy\\u00e9s aux joueurs de l''\\u00e9quipe de France et aux \\u00e9quipes nationales. ","phenomenal":"En collaboration avec l\\u2019\\u00e9ducation nationale, l\\u2019USEP 86 et le comit\\u00e9 d\\u00e9partementale de Handball, le CDOS Vienne a pour projet de rencontrer les \\u00e9l\\u00e8ves et les enseignants au sein des classes afin d\\u2019animer des ateliers de d\\u00e9couverte du Handball : explication des r\\u00e8gles du jeu, d\\u00e9couverte des membres qui constituent notre \\u00e9quipe de France et travail sur la mixit\\u00e9 au sein de cette \\u00e9quipe.\\n\\nDans un deuxi\\u00e8me temps, les \\u00e9l\\u00e8ves seront film\\u00e9s, apr\\u00e8s accord des parents sur le droit \\u00e0 l\\u2019image, afin qu\\u2019ils transmettent des messages d\\u2019encouragement et de bienvenue aux diff\\u00e9rentes \\u00e9quipes lors du mondial. Un travail sera ainsi fait en parall\\u00e8le afin de r\\u00e9diger leurs messages en anglais.\\n\\nLes vid\\u00e9os seront ensuite diffus\\u00e9es sur une page FaceBook cr\\u00e9\\u00e9e pour l\\u2019occasion, qui sera r\\u00e9guli\\u00e8rement aliment\\u00e9e des actualit\\u00e9s et de l\\u2019avancement du projet.","quisuisje":"AutreAssociationSportive","partners":"USEP 86 - DSDEN 86 - CD Handball 86","participants":"480"}'),
(149642, '{"citation":"places pour le mondial","phenomenal":"mosaique pour les licenci\\u00e9s\\nstand d''information","quisuisje":"clubcomite","partners":"ville","participants":"100"}'),
(149754, '{"citation":"En devenant acteur du hand, j\\u2019ai la possibilit\\u00e9 de devenir spectateur\\u2026.","phenomenal":"JOUER : Faire pratiquer l''activit\\u00e9 \\u00e0 nos \\u00e9l\\u00e8ves.\\n\\nENCOURAGER : Participer \\u00e0 un des matchs du mondial en tant que supporter actif.\\n\\nARBITRER : Organiser un tournoi dans l''\\u00e9cole o\\u00f9 nos \\u00e9l\\u00e8ves seront arbitres.\\n\\nPARTICIPER : une grande journ\\u00e9e inter-hand doit \\u00eatre organis\\u00e9e par la circonscription du 18\\u00e8me et l''USEP\\n","quisuisje":"Ecole","partners":"circonscription du 11\\u00e8me, du 18\\u00e8me et l\\u2019Usep","participants":"70"}'),
(149789, '{"citation":"Dotation mat\\u00e9rielle","phenomenal":"Travail culturel sur les pays engag\\u00e9s dans la comp\\u00e9tition.","quisuisje":"usep","partners":"Comit\\u00e9 d\\u00e9partemental, Handball 01","participants":"634"}'),
(149797, '{"citation":"Obtenir des places pour un match du championnat du monde de handball  pour les \\u00e9l\\u00e8ves de 6\\u00e8me licenci\\u00e9s \\u00e0 l''association sportive et ayant particip\\u00e9s \\u00e0 l''organisation du tournoi et \\u00e0 l''arbitrage des rencontres (Environ 25 places).","quisuisje":"AutreAssociationSportive","participants":"280","phenomenal":"Articles dans le journal du coll\\u00e8ge, articles sur le site de l''\\u00e9tablissement (r\\u00e9alis\\u00e9s par les jeunes reporters de l''association sportive).\\nAffiches, panneaux dans l''\\u00e9tablissement (r\\u00e9alis\\u00e9s par les \\u00e9l\\u00e8ves internes)","partners":"Comit\\u00e9 D\\u00e9partemental d''Indre et Loire de Handball (pr\\u00eat de mat\\u00e9riel)."}'),
(149852, '{"citation":"Vibrer pour une \\u00e9quipe dans cette comp\\u00e9tition\\nprendre du plaisir \\u00e0 pratiquer le hand","quisuisje":"Ecole","participants":"120","phenomenal":"Suivi des r\\u00e9sultats du mondial \\u00e0 l''\\u00e9cole"}'),
(149860, '{"citation":"(re)d\\u00e9couvrir, s''amuser et pratiquer le handball, ensemble!","phenomenal":"- Stand d''information sur la billetterie mondial\\n- Affichage dans les salles de la communes des affiches et banderoles sur le mondial\\n- Jeu \\u00e0 la mi-temps des matches avec notre mascotte pour promouvoir le mondial ","quisuisje":"club","partners":"Commune de Wallers Arenberg","participants":"30"}'),
