(149895, '{"citation":"assister \\u00e0 un match de handball\\navoir des lots \\nparticiper \\u00e0 un \\u00e9v\\u00e9nement festif qui rassemble quelque soient les diff\\u00e9rences.","quisuisje":"Autre","phenomenal":"ateliers autour du handball\\nfaire venir un(e) handballeur(euse)\\nA titre personnelle je pratique le handball de haut niveau","partners":"les 25 \\u00e9tablissements scolaires partenaires de Cit\\u00e9o, les instituts m\\u00e9dico sp\\u00e9cialis\\u00e9s, K\\u00e9olis-Lille, Kipstadium, les villes de Lille, Roubaix, Villeneuve d''Ascq, Mons-en-Baroeul, Halluin, Hellemmes, Wattrelos.","participants":"400"}'),
(149912, '{"citation":"Assister \\u00e0 un match du Mondial 2017 de handball","phenomenal":"\\u00c9tant \\u00e9loign\\u00e9 des sites, notre action sera limit\\u00e9e. Nous communiquerons sur l''\\u00e9v\\u00e8nement via le kit com que nous recevrons et sur les horaires des matchs de l''\\u00e9quipe de France.","quisuisje":"Collectivite","participants":"50"}'),
(149931, '{"citation":"De pouvoir contribuer \\u00e0 l''int\\u00e9gration sociale des personnes en situation de handicap et de leur apporter du plaisir \\u00e0 pratiquer un sport exemplaire","phenomenal":"Participation au Road Show, participation \\u00e0 la Mosa\\u00efque, participation aux Rencontres Nationales Ph\\u00e9nom\\u00e9nales","quisuisje":"clubligue","partners":"Comit\\u00e9 R\\u00e9gional de Sport Adapt\\u00e9, Comit\\u00e9 R\\u00e9gional Handisport, FFHB, Keneo","participants":"576"}'),
(149938, '{"citation":"Plaisir,Fraternit\\u00e9, Echange, Citoyennet\\u00e9","phenomenal":"FACEBOOK\\/TWITTER\\nUne diffusion r\\u00e9guli\\u00e8re voir quotidienne de nos actions sera r\\u00e9alis\\u00e9e par le biais de la page facebook et Twitter de l\\u2019UGSEL Marne.\\nNous diffuserons les photos des diff\\u00e9rentes animations propos\\u00e9es de la maternelle jusqu\\u2019au Lyc\\u00e9e ainsi qu\\u2019un partage des posts de la page \\u00ab France 2017 Handball \\u00bb\\nChaque diffusion d\\u2019article ou des m\\u00e9dias sera compl\\u00e9t\\u00e9e par des hashtags en lien avec le mondial de handball 2017\\n#handball2017 #tousprets  #phenomenalhandball #Ugselmarne\\n\\nUGSEL TV - Chaine Youtube\\nChaque action li\\u00e9e au projet \\u00ab La T\\u00eate et le Hand \\u00bb donnera lieu \\u00e0 la cr\\u00e9ation d\\u2019un vid\\u00e9o clip promotionnel qui sera ajout\\u00e9 \\u00e0 notre chaine Youtube UGSEL Marne.\\nEch\\u00e9ancier de diffusion des clips\\nBabyHand \\u2013 Handball 1er Pas   Janvier 2017 \\nHandball Coll\\u00e8ge F\\u00e9vrier 2017\\nNational de Handball CJF Avril 2017 \\nClip La T\\u00eate et le Hand 2016\\/2017   Juin 2017\\n\\nSITE INTERNET WWW.UGSELMARNE.ORG\\nL\\u2019ensemble des informations, documents, photos et vid\\u00e9os seront diffus\\u00e9s sur le site internet de l\\u2019UGSEL Marne et plus particuli\\u00e8rement sur la page d\\u00e9di\\u00e9 \\u00ab La T\\u00eate et le Hand \\u00bb\\nChaque enseignant pourra y trouver des outils p\\u00e9dagogiques pour la \\nmise en place de ses s\\u00e9ances de Handball \\n\\n","quisuisje":"ugsel","partners":"CNDS - COMITE MARNE HAND - LIGUE CHAMPAGNE HAND","participants":"1500"}'),
(149949, '{"citation":"Vivre un moment fort dans la promotion de leur activit\\u00e9 et participer \\u00e0 la communication de la Ligue sur cet \\u00e9v\\u00e9nement. Cr\\u00e9er un r\\u00e9seau d''\\u00e9changes de bonnes pratiques pour dynamiser leur club. Devenir les acteurs de leur d\\u00e9veloppement\\nVivre l\\u2019\\u00e9v\\u00e9nement ph\\u00e9nom\\u00e9nale au plus pr\\u00e8s en participant \\u00e0 un match en m\\u00e9tropole.","phenomenal":"Organisation de Tournoi avec les \\u00e9coles, En faire la promotion sur les r\\u00e9seaux sociaux.","quisuisje":"clubligue","partners":"DJSCS Guadeloiupe","participants":"20"}'),
(149956, '{"citation":"De passer des moment d\\u2019exception avec l''\\u00e9quipe de France masculine et ses 2 titres olympique et 4  X champion du monde.D''un grand moment sportif avec plein d\\u2019\\u00e9motions et de frissons.","quisuisje":"club","partners":"Ville,divers sponsor","participants":"100","phenomenal":"Distribution de flyers\\/Affichage dans le hall du Gymnase\\/"}'),
(149958, '{"citation":"Ce serait l''occasion de pouvoir assister \\u00e0 un match du Mondial au Stade Pierre Mauroy mais aussi de sensibiliser les jeunes \\u00e0 l''activit\\u00e9 physique et sportive.","quisuisje":"Collectivite","participants":"200","partners":"Ecoles Primaires St Luc, Paul Bert, Le Petit Prince, ALSH de la Commune de Lys Lez Lannoy, Coll\\u00e8ge Gambetta, Ligue Handisport","phenomenal":"R\\u00e9alisation d''affiche afin de mettre en avant les valeurs du sport. Cette action s''inscrit dans un programme annuel de sensibilisation des jeunes aux valeurs du sport (un travail en amont et en aval de la journ\\u00e9e est pr\\u00e9vu)"}'),
(149963, '{"citation":"S''engager pour un projet soci\\u00e9tal et contre une probl\\u00e9matique grave en utilisant le Handball comme outil, c''est participer \\u00e0 un projet citoyen !","quisuisje":"club","partners":"Publics, institutionnels et priv\\u00e9s","participants":"300","phenomenal":"Inviter les participants \\u00e0 un match du mondial. \\nMettre en place un stand d''information sur la billetterie."}'),
