(150136, '{"citation":"Pratiquez, vivez, vibrez, respectez ","phenomenal":"Participation de licenci\\u00e9s (rencontre, interview) r\\u00e9compenses ( kit jeu et verres ecocup mondial 2017)","quisuisje":"usep","partners":"Office municipal de Miramas, service des sports de Miramas, le club de hand de Miramas,la ligue de Provence de handball","participants":"200"}'),
(150151, '{"citation":"La promesse faire aux participants est de participer \\u00e0 la mosa\\u00efque ph\\u00e9nom\\u00e9nal.\\nLa participation \\u00e0 un \\u00e9v\\u00e9nement international. ","phenomenal":"Information sur l''\\u00e9v\\u00e9nement Mondial 2017.\\nParticipation \\u00e0 la mosa\\u00efque Ph\\u00e9nom\\u00e9nal.\\n","quisuisje":"club","partners":"\\u00c9coles primaires des diff\\u00e9rentes commune, la Communaut\\u00e9 Creusot-Montceau, politique de la ville, \\u00e9ducation nationale","participants":"100"}'),
